def compute_score() -> tuple[str, float]:
    from rubric.utils.llm_tools import vlm_call
    # Use VLM to compare original vs modified slide 10 and verify that the
    # bullet "Objects include CSS files, JavaScript files, images, videos"
    # was added in a visually and semantically appropriate place.
    slide_number = 10

    original_image = None
    modified_image = None

    # Find slide 10 in original screenshots (robust to object/dict entries)
    for s in original_ppt_screenshots:
        try:
            s_num = getattr(s, "slide_number", None)
            if s_num is None and isinstance(s, dict):
                s_num = s.get("slide_number")
            if s_num == slide_number:
                original_image = getattr(s, "image_path", None)
                if original_image is None and isinstance(s, dict):
                    original_image = s.get("image_path") or s.get("path")
                break
        except Exception:
            continue

    # Find slide 10 in modified screenshots (robust to object/dict entries)
    for s in modified_ppt_screenshots:
        try:
            s_num = getattr(s, "slide_number", None)
            if s_num is None and isinstance(s, dict):
                s_num = s.get("slide_number")
            if s_num == slide_number:
                modified_image = getattr(s, "image_path", None)
                if modified_image is None and isinstance(s, dict):
                    modified_image = s.get("image_path") or s.get("path")
                break
        except Exception:
            continue

    if not modified_image:
        return ("Modified slide 10 screenshot not found.", 0.0)
    if not original_image:
        return ("Original slide 10 screenshot not found.", 0.0)

    target_bullet = "Objects include CSS files, JavaScript files, images, videos"

    prompt = (
        "Compare two images of the same PowerPoint slide (slide 10):\n"
        "Image A is the original; Image B is the modified.\n\n"
        "Task:\n"
        f"1) Determine if a bullet with EXACT text:\n\"{target_bullet}\"\n"
        "   is present in Image B but NOT present in Image A.\n"
        "2) If present, judge whether its placement is visually and semantically appropriate\n"
        "   relative to the existing bullets and content (i.e., appears as part of the same list/group,\n"
        "   consistent alignment/indentation, reasonable ordering among similar items, not isolated or\n"
        "   in an unrelated area like title/header/legend/footnote).\n\n"
        "Instructions:\n"
        "- Ignore minor formatting/style differences.\n"
        "- Base your judgment on visual grouping, proximity, alignment, and content coherence.\n\n"
        "Respond with ONE of the following labels ONLY (uppercase), followed by a brief justification:\n"
        "- PRESENT_AND_APPROPRIATE: the exact bullet is newly present and its placement is appropriate.\n"
        "- PRESENT_BUT_INAPPROPRIATE: the exact bullet is newly present but placement is inappropriate.\n"
        "- NOT_PRESENT: the exact bullet is not present in the modified slide.\n"
    )

    try:
        response = vlm_call(images=[original_image, modified_image], prompt=prompt, temperature=0.1, max_tokens=300)
        resp = str(response).strip().upper()
        if resp.startswith("PRESENT_AND_APPROPRIATE"):
            return response, 1.0
        if resp.startswith("PRESENT_BUT_INAPPROPRIATE"):
            return response, 0.5
        if resp.startswith("NOT_PRESENT"):
            return response, 0.0
        # Fallback: try simple YES/NO detection if labels weren't followed
        low = resp.lower()
        if "present" in low and "appropriate" in low:
            return response, 1.0
        if "present" in low and "inappropriate" in low:
            return response, 0.5
        if low.startswith("yes"):
            return response, 0.6
        if low.startswith("no"):
            return response, 0.0
        return f"Unclear VLM response: {response}", 0.0
    except Exception as e:
        return (f"Error during VLM comparison: {str(e)}", 0.0)

