def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    n = min(len(orig.slides), len(mod.slides))
    # Check for slide additions/removals
    if len(orig.slides) != len(mod.slides):
        return ("Number of slides changed.", 0.0)
    # Check each non-10 slide for changes
    for i in range(n):
        if i == 9:
            continue  # skip slide 10
        orig_slide = orig.slides[i]
        mod_slide = mod.slides[i]
        # Check text differences
        orig_texts = []
        for shape in orig_slide.shapes:
            if shape.has_text_frame:
                orig_texts.extend([p.text.strip() for p in shape.text_frame.paragraphs if p.text.strip()])
        mod_texts = []
        for shape in mod_slide.shapes:
            if shape.has_text_frame:
                mod_texts.extend([p.text.strip() for p in shape.text_frame.paragraphs if p.text.strip()])
        if set(orig_texts) != set(mod_texts):
            return (f"Text changed on slide {i+1}.", 0.0)
        # Check for shapes/images
        if len(orig_slide.shapes) != len(mod_slide.shapes):
            return (f"Shapes/images changed on slide {i+1}.", 0.0)
    # Also check for animations/transitions globally except on slide 10
    for anim in ppt_diff.added_animations + ppt_diff.removed_animations:
        if anim.slide_id and anim.slide_id != orig.slides[9].slide_id:
            return (f"Animation change on slide not 10.", 0.0)
    for t in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if t.slide_id and t.slide_id != orig.slides[9].slide_id:
            return (f"Transition change on slide not 10.", 0.0)
    return ("No extraneous changes to other slides.", 1.0)
